// File: peek_network.dart
// Run: dart peek_network.dart example.com
import 'dart:io';

void main(List<String> args) async {
  final host = args.isNotEmpty ? args[0] : 'example.com';
  print('--- Application layer (you) ---');
  print('You want to visit:  $host');

  print('\n--- Application layer (DNS) ---');
  final addrs = await InternetAddress.lookup(host);
  final ip = addrs.first.address;
  print('DNS resolved  ->  $ip');

  print('\n--- Transport layer (TCP) ---');
  final t0 = DateTime.now();
  final socket = await Socket.connect(ip, 80);
  final ms = DateTime.now().difference(t0).inMilliseconds;
  print('TCP connected to $ip:80 in ${ms}ms');
  print('Local end  -> ${socket.address.address}:${socket.port}');
  print('Remote end -> ${socket.remoteAddress.address}:${socket.remotePort}');
  print('That 4-tuple + protocol = the 5-tuple that identifies this connection.');

  print('\n--- Application layer (HTTP) ---');
  socket.write('GET / HTTP/1.1\r\nHost: $host\r\nConnection: close\r\n\r\n');
  final response = await socket.fold<List<int>>(<int>[], (a, b) => a..addAll(b));
  final text = String.fromCharCodes(response);
  print('Got ${text.length} bytes back. First line:');
  print('  ${text.split("\n").first}');

  await socket.close();
}

// Typical output:
